import { Agent, Hashtags, positionWatch, flyTo, killSome, map, disableNotifications, updateLocation, networkPromise, addShim, toggle, announce, delay, drop, gotFile, Marker, updateSubscriptions, showMessage, type, uuidv4 } from 'scripting';

// Run alert-bot on the network, eg., npm run ki1r0y
//   (You don't really need all the demo-data.js. Just the part labeled movie setup.)
// Select this script from the app's on-board script runner.
// When ready for recording, click the black screen.
// When "Maya" needs to take the picture of the police line, you need to click the attachments chooser and pick a file, as this cannot be automated.

async function run() {
  // Setup.

  const maya = Agent.ensure('6f194f1c-6fb7-4435-85da-3ef8afd249e8');
  const david = Agent.ensure('7296470f-f4f1-42f7-b688-c5a5ebb81155');
  const rosa = Agent.ensure('0a91f386-38a7-4344-b014-8402fbc24fbb');
  const anon = Agent.ensure('869a2d28-c45f-4070-a321-0a0378a5ef53'); //'80878918-fa68-4f3a-b3b5-13d36e6436d7');
  maya.updateValue(ma, 'public', 'avatar');
  david.updateValue(da, 'public', 'avatar');
  rosa.updateValue(ra, 'public', 'avatar');
  Agent.switchUser(maya.tag);
  
  
  // Set the hashtags we want.
  Hashtags.hashtags = {};
  Hashtags.canonical2extended = {};
  Object.entries({"🪧 rally":"pub","⛔️ avoid":true,"🏥 hospital":false,"🚻 restroom":false}).forEach(([tag, active]) => Hashtags.add(tag, active, false));
  Hashtags.resetSubscriberDisplay();
  // Turn off geolocation movment, and instead set our own map position/zoom, and location marker position.
  navigator.geolocation.clearWatch(positionWatch);
  map.setView([42.08373217231411, -67.27210342884065], 2);
  disableNotifications(true);
  updateLocation(37.77873502340792, -122.41476953029634);
  const contact = await networkPromise;
  const issuedTime = Date.now();
  // Wait until a click so that recording can be started.
  // Can't announce until there is a page interaction anyway.
  const {promise, resolve} = Promise.withResolvers();
  let shim = addShim();
  shim.onclick = async event => {
    event.stopPropagation();
    event.preventDefault();
    resolve();
  };
  await promise;
  await toggle('avoid'); // Need 'avoid' on at start in order to find any from previous session so we can destroy them.

  await announce("Scene 1 has no mobile display. Drone shot over thousands of people filling a city street. Banners, signs, colour. Peaceful energy. The camera slowly descends into the crowd.");
  await delay();
  shim.remove();

  await announce("Scene 2, featuring Maya's phone. Quick intercutting: Maya at the front of the march (phone in hand, alert app open). David + daughter in the middle. Rosa the medic two blocks back near a first-aid station.");
  await flyTo({lat: 37.783230441289334, lng: -122.40973257488805}, 14); // turn on hospital
  await toggle('hospital');
  await flyTo({lat: 37.783518365054405, lng: -122.41091760508426}, 15); // togle rally, add restroom
  await toggle('rally');
  await toggle('rally');
  await toggle('restroom');
  await toggle('avoid');

   await announce("Scenes 3 and 4, featuring Maya's phone. At the front, the crowd is compressing. A police line has formed and is slowly advancing. We watch Maya tag the location, take a photo through the crowd, type fast, and hit send. Her hand is shaking slightly.");
  await flyTo({lat: 37.78343528005088, lng: -122.41256436944242}, 16);
  updateLocation(37.77960208641734, -122.41359472274782);
  const mayaAlert = await drop({lat: 37.780462779492645, lng: -122.41257548332216, tag: 'avoid', open: true});
  console.log('mayaAlert:', mayaAlert);
  await gotFile();
  delay();
  await Promise.all([
    type("Line forming on market near 7th, pushing us back towards city hall. Avoid front."),
    delay().then(async () => { // While the typing happens, two pins are dropped by others.
      await delay(1600);
      await drop({lat: 37.77922897497529, lng: -122.4109983444214, tag: 'avoid'});
      await delay(1600);
      updateLocation(37.77958512684719, -122.41383075714111);
      await delay();
      await drop({lat: 37.78005999334045, lng: -122.41350889205934, tag: 'avoid'});
    })
  ]);
  await delay();
  Marker.closePopup();
  await delay();

  shim = addShim();
  Agent.switchUser(david.tag);
  await announce("Scene 5, featuring David's phone. In the middle of the crowd, David's phone buzzes. He reads the alert, looks ahead — can't see anything yet. He looks at his daughter. He takes her hand and they start moving sideways toward a side street. He doesn't need to understand everything. The alert gave him 90 seconds he didn't have before.");
  updateLocation(37.7786080869364, -122.41506959162508);
  //await flyTo({lat: 37.78179176051859, lng:-122.41251885079693}, 16);
  disableNotifications(false);
  const wrapper = Marker.markers[mayaAlert];
  const reply = wrapper.replies[wrapper.replies.length - 1];
  const message = reply.payload.message;
  const act = reply.act;
  console.log({wrapper, reply, act});
  const {promise:notificationPromise, resolve:notificationResolve} = Promise.withResolvers();
  wrapper.resolveGo = notificationResolve;
  wrapper.showNotification({body: message, act: 'fixme'});
  await notificationPromise;
  shim.remove();
  disableNotifications(true);
  await delay(1600);
  Marker.closePopup();

  Agent.switchUser(rosa.tag);
  flyTo({lat: 37.78026774129636, lng: -122.4144849253935}, 16);
  await announce("Scene 6, featuring Rosa's phone. Rosa opens the app. She sees a message that says that the appp site is down, and that she entered through an alternative portal. She sees another alert come in.");
  updateLocation(37.780284700709906, -122.41667360794965);
  updateSubscriptions(undefined, []);
  await delay();
  showMessage("CivilDefense.io is down. Entering through alternative portal at ki1r0y.com.", 'loading');
  updateSubscriptions([]);
  await delay(1600);
  await drop({lat: 37.779519639310344, lng: -122.4138297067839, tag: 'avoid'});

  await announce("Scene 7, featuring David's phone. The alert Maya posted has grown a reply thread. We see it building: David confirms the side street is clear. Rosa reports she's moving up to help. An anonymous user posts that Howard Street is completely open. The map updates with a green suggested route. No one is in charge. Everyone is helping.");
  Agent.switchUser(david.tag);
  updateLocation(37.777120433667385, -122.4127373162628);
  await flyTo({lat: 37.78179176051859, lng:-122.41251885079693}, 16);
  Marker.openPopup(mayaAlert);
  await delay();
  await type("Side street is clear."),
  await delay();
  await contact.publish({eventName: mayaAlert, subject: uuidv4(), payload: "I'm a medic. Headed to the front now.",  act: rosa.tag});
  await delay();
  await contact.publish({eventName: mayaAlert, subject: uuidv4(), payload: "Howard street is completely open. I'm going to mark it #clear.",  act: anon.tag});
  await delay(1600);
  Marker.closePopup();
  await delay();
  await flyTo({lat: 37.780250633339136, lng: -122.41094276585501}, 16);
  drop({lat: 37.77624401564148, lng: -122.41162061691286, tag: '✅ clear', act: anon.tag});
  drop({lat: 37.77774798714829, lng: -122.40976025808779, tag: '✅ clear', act: anon.tag});
  drop({lat: 37.77947621555006, lng: -122.40755719794835, tag: '✅ clear', act: anon.tag});
  await type("clear", Hashtags.chipset.firstChild);
  await drop({lat: 37.77758387025088, lng: -122.41333723068239, tag: 'clear', act: david.tag});

  await announce("Scene 8, featuring David's phone. David and his daughter, and a dozen others who got the same alert, are walking calmly down a quiet side street. No panic. They found it because they knew before they needed to know. David exhales. His daughter points at something on his phone — curious.");
  await flyTo({lat: 37.781364179456276, lng:-122.40983872186919}, 15);
  await drop({lat: 37.781233732276135, lng: -122.40533494128614, tag: 'clear', act: anon.tag});
  updateLocation(37.7908801, -122.4201728);
  //await drop({lat: 37.78285825179079, lng: -122.40327358245851, tag: 'clear', act: anon.tag});
  updateLocation(37.781654165684806, -122.40475416183472);
  await drop({lat: 37.78468571606582, lng: -122.40451647725425, tag: 'clear', act: anon.tag});
  updateLocation(37.78240036220268, -122.40385293960573);
  await drop({lat: 37.78622281918263, lng: -122.40636538332184, tag: 'clear', act: anon.tag});

  await announce("Scene 9. The crowd's distributed awareness, made legible. This is what the community built together in 20 minutes, without a coordinator, without infrastructure.");
  await flyTo({lat: 7.184375275650273, lng:-55.63445448875428}, 2 );
  await announce('DONE!');

  // Now clean up what we did.
  await flyTo({lat: 37.781364179456276, lng:-122.40983872186919}, 15); // Get in the right position to kill stuff.
  await killSome('avoid');
  await killSome('clear');
}

const ma = 'data:image/png;base64,';
const da = 'data:image/jpeg;base64,';
const ra = 'data:image/jpeg;base64,';

run();
